# settings.py
from pydantic_settings import BaseSettings
from pydantic import Field, field_validator
import re

class Settings(BaseSettings):
    # LLM provider key — must look like a valid key (non-empty, not a placeholder)
    llm_api_key: str = Field(..., min_length=20)
    # Search key
    search_api_key: str = Field(..., min_length=10)
    # Vector DB key
    vector_db_api_key: str = Field(..., min_length=10)

    model_config = {"env_file": ".env", "env_file_encoding": "utf-8"}

    @field_validator("llm_api_key")
    @classmethod
    def no_placeholder(cls, v: str) -> str:
        if v.lower() in {"your-key-here", "changeme", "todo", "..."}:
            raise ValueError("llm_api_key is a placeholder — set a real key")
        return v

# Singleton — imported everywhere, validated once
settings = Settings()

# clients.py
import httpx
from .settings import settings

def _make_llm_client() -> httpx.Client:
    return httpx.Client(
        base_url="https://api.anthropic.com",
        headers={
            "x-api-key": settings.llm_api_key,
            "anthropic-version": "2023-06-01",
        },
        timeout=60.0,
    )

def _make_search_client() -> httpx.Client:
    return httpx.Client(
        base_url="https://api.search.example",
        headers={"Authorization": f"Bearer {settings.search_api_key}"},
        timeout=10.0,
    )

# Module-level singletons — created once, reused across requests
llm_client = _make_llm_client()
search_client = _make_search_client()

import logging
import re
from typing import Any

_KEY_PATTERN = re.compile(r'(sk-|ant-|agt-|Bearer\s)[A-Za-z0-9+/=_-]{10,}')

class RedactKeyFilter(logging.Filter):
    """Redact API key values in any log record message or extra fields."""
    def filter(self, record: logging.LogRecord) -> bool:
        record.msg = _redact(str(record.msg))
        if record.args:
            record.args = tuple(_redact(str(a)) for a in record.args)
        return True

def _redact(text: str) -> str:
    return _KEY_PATTERN.sub(r'\1[REDACTED]', text)

# Attach filter to every handler
for handler in logging.root.handlers:
    handler.addFilter(RedactKeyFilter())

import httpx

def call_with_key_error_handling(client: httpx.Client, path: str, **kwargs) -> dict:
    try:
        resp = client.post(path, **kwargs)
        resp.raise_for_status()
        return resp.json()
    except httpx.HTTPStatusError as exc:
        if exc.response.status_code == 401:
            raise RuntimeError(
                f"API key invalid or revoked for {path}. Rotate the key and redeploy."
            ) from exc
        if exc.response.status_code == 403:
            raise RuntimeError(
                f"API key lacks permission for {path}. Check key scope settings."
            ) from exc
        if exc.response.status_code == 429:
            # surface rate-limit details to the caller for retry logic
            retry_after = exc.response.headers.get("retry-after", "unknown")
            raise RuntimeError(
                f"Rate limited on {path}. Retry after {retry_after}s."
            ) from exc
        raise
